import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const smallcapsRole = {
    name: 'smallcaps',
    alias: ['sc'],
    options: { ...commonRoleOptions('smallcaps') },
    body: {
        type: 'myst',
        required: true,
    },
    run(data) {
        const node = { type: 'smallcaps', children: data.body };
        addCommonRoleOptions(data, node);
        return [node];
    },
};
